### Fix 2: GlobalBus subscriber isolation
File: packages/opencode/src/bus/global.ts

Replace the entire `GlobalBusEmitter` class with:

```ts
class GlobalBusEmitter extends EventEmitter<{
  event: [GlobalEvent]
}> {
  override emit(eventName: "event", event: GlobalEvent): boolean {
    if (event.payload && typeof event.payload === "object" && !("id" in event.payload)) {
      event.payload.id = event.payload.syncEvent?.id ?? Identifier.create("evt", "ascending")
    }
    // Invoke each listener individually so one throw doesn't kill remaining listeners
    const listeners = this.rawListeners(eventName) as Array<(event: GlobalEvent) => void>
    if (listeners.length === 0) return false
    for (const listener of listeners) {
      try {
        listener(event)
      } catch (error) {
        console.error("[GlobalBus] subscriber error:", error)
      }
    }
    return true
  }
}
```

### Fix 3: Campaign orchestrator store race
File: packages/opencode/src/campaign/orchestrator.ts

Change the import from:
`import { Context, Effect, Layer, Ref } from "effect"`
to:
`import { Context, Effect, Layer, SynchronizedRef } from "effect"`

Change `store` initialization from:
`const store = yield* Ref.make<Map<string, OrchestratorCampaignState>>(new Map())`
to:
`const store = yield* SynchronizedRef.make<Map<string, OrchestratorCampaignState>>(new Map())`

Change `getState` function. Replace the `Ref.get(store)` call to use `SynchronizedRef.get(store)`:
```ts
function getState(campaignId: string): Effect.Effect<OrchestratorCampaignState, CampaignNotFound> {
  return Effect.fnUntraced(function* () {
    const map = yield* SynchronizedRef.get(store)
    const state = map.get(campaignId)
    if (!state) return yield* Effect.fail(new CampaignNotFound(campaignId))
    return state
  })
}
```

Change `updateState` to use `SynchronizedRef.modify` for atomic update:
```ts
function updateState(
  campaignId: string,
  update: (state: OrchestratorCampaignState) => OrchestratorCampaignState,
): Effect.Effect<OrchestratorCampaignState, CampaignNotFound> {
  return Effect.fnUntraced(function* () {
    const result = yield* SynchronizedRef.modify(store, (map) => {
      const existing = map.get(campaignId)
      if (!existing) {
        return [Effect.fail(new CampaignNotFound(campaignId)) as any, map] as const
      }
      const next = new Map(map)
      const updated = update(existing)
      next.set(campaignId, updated)
      return [Effect.succeed(updated), next] as const
    })
    return result
  })
}
```

Also, any code that was using `Ref` syntax now uses `SynchronizedRef` — check the rest of the file for any other Ref.get/store.set calls and update them.

